INSERT INTO public.question_bank_questions (product_slug, bank_type, category, question, options, correct_answer, explanation, sort_order) VALUES
('platinum-wealth-venture','exam','suitability','Which client is least suitable for PWV?','["A pre-retiree planning future supplemental income","A business owner with surplus cash and long-term goals","A client who needs most of the capital for a property purchase in 2 to 3 years","A client interested in legacy planning"]'::jsonb,2,'PWV is generally less suitable for capital likely to be needed in the short term. The plan is better matched to medium-to-long-term wealth accumulation rather than near-term liquidity needs.',36),
('platinum-wealth-venture','exam','suitability','What is the most important suitability check before recommending PWV?','["Whether the client likes the dividend feature","Whether the client can comfortably sustain the 5-year premium commitment without affecting emergency or short-term funds","Whether the client already owns another ILP","Whether the client wants the highest bonus tier"]'::jsonb,1,'A strong recommendation should be based on affordability, liquidity, and planning fit, not just attractive features.',37),
('platinum-wealth-venture','exam','compliance','Which statement should an advisor avoid when presenting PWV?','["PWV is a market-linked plan, so values can fluctuate.","We should first see whether this fits your goals and cash flow.","You can use this as both your emergency reserve and your long-term wealth plan.","It may play a role in retirement or legacy planning if suitable."]'::jsonb,2,'Emergency liquidity and long-term investing should generally be separated. That statement reflects poor planning and unsuitable positioning.',38),
('platinum-wealth-venture','exam','advisory-skills','A client already has a private banker, fixed deposits, and existing policies. What is the best advisory approach before recommending PWV?','["Present PWV immediately because wealthy clients usually qualify","Focus only on the dividend angle","Review what the client already has and identify whether PWV fills a real planning gap","Recommend replacing the weakest-looking product first"]'::jsonb,2,'A mature advisor sells into a genuine gap rather than assuming every affluent client needs the same solution.',39),
('platinum-wealth-venture','exam','closing','A client says, "I like the concept, but I want to review my numbers first." What is the best response?','["You should start first and think later.","No problem — let''s review your cash flow properly and decide whether the amount is comfortable.","If you wait, you probably aren''t serious.","The product is too complex to review on your own."]'::jsonb,1,'This is a respectful, advisory-style close that keeps the process moving without pressure.',40),
('platinum-wealth-venture','exam','suitability','A client says, "I never want to see my investment value go down." What should the advisor conclude?','["PWV is ideal because of the bonuses","PWV may not fit the client''s expectations unless risk and volatility are properly understood","The client should choose the highest premium tier","The client only needs the dividend fund"]'::jsonb,1,'Since PWV is market-linked, the client must understand that policy value can fluctuate. This is a core suitability issue.',41),
('platinum-wealth-venture','exam','compliance','A client asks whether PWV dividends can definitely fund future healthcare premiums. What is the best response?','["Yes, the income fund will cover those premiums","Dividends are not guaranteed, so they may support future planning but should not be presented as certain outcomes","Yes, if the client starts early enough","No, dividends are irrelevant to retirement planning"]'::jsonb,1,'This is the compliant and realistic way to present dividend-based planning.',42),
('platinum-wealth-venture','exam','advisory-skills','What is the best first discovery question before pitching PWV to a pre-retiree?','["Do you want the dividend fund or growth fund?","What are the biggest financial concerns you see in retirement?","Would you like the highest welcome bonus first?","How much do you want to invest today?"]'::jsonb,1,'This opens a planning conversation and helps the advisor connect PWV, if suitable, to a real client concern.',43);